const { v4: uuidv4 } = require('uuid');
return [{
  json: {
    correlationId:    uuidv4(),
    startedAt:        new Date().toISOString(),
    executionId:      $execution.id,
    workflowName:     'WF-05-ai-prediction-engine',
    predictionWindow: 120,  // gera previsões para jogos nas próximas 2h
    rateLimitKey:     'wcic:rl:wf05:openai',
  }
}];

const matches = $input.all();
const initData = $('Init').first().json;

if (matches.length === 0 || !matches[0].json.match_id) {
  console.log('[WF-05] Nenhuma partida elegível para previsão');
  return [{ json: { hasMatches: false, ...initData } }];
}
return [{ json: { hasMatches: true, matchCount: matches.length, ...initData } }];

// ============================================================
// Agrega todos os dados coletados em um único feature set
// para passar ao SWF Match Predictor
// ============================================================
const matchData  = $('Split by Match').item.json;
const statsRows  = $('Fetch Match Stats').all().map(i => i.json);
const newsRows   = $('Fetch News Context').all().map(i => i.json);
const sentRows   = $('Fetch Sentiment Context').all().map(i => i.json);

const stats = statsRows[0] || {};

// Calcula pontos da forma recente
const calcFormPts = (formArr) => (formArr || []).reduce((acc, r) => acc + (r==='W'?3:r==='D'?1:0), 0);

// Organiza sentimento por team_id
const sentMap = {};
for (const s of sentRows) {
  if (!sentMap[s.entity_id]) sentMap[s.entity_id] = s;
}

// Detecta notícias de lesão/suspensão por time
const hasAlert = (teamId) => newsRows.some(n =>
  n.is_alert && Array.isArray(n.affected_team_ids) && n.affected_team_ids.includes(teamId)
);

const enrichedStats = {
  ...stats,
  home_form_pts: calcFormPts(stats.home_form),
  away_form_pts: calcFormPts(stats.away_form),
  home_has_injury_news: hasAlert(matchData.home_team_id),
  away_has_injury_news: hasAlert(matchData.away_team_id),
  home_suspended_count: 0, // Sprint 6: popular via players.is_suspended
  away_suspended_count: 0,
  home_sentiment_score: sentMap[matchData.home_team_id]?.positive_ratio || null,
  away_sentiment_score: sentMap[matchData.away_team_id]?.positive_ratio || null,
  home_news_impact_avg: newsRows.filter(n => (n.affected_team_ids||[]).includes(matchData.home_team_id)).reduce((a,n,_,arr) => a + n.impact_score/arr.length, 0) || null,
  away_news_impact_avg: newsRows.filter(n => (n.affected_team_ids||[]).includes(matchData.away_team_id)).reduce((a,n,_,arr) => a + n.impact_score/arr.length, 0) || null,
};

return [{
  json: {
    match_id:           matchData.match_id,
    home_team:          matchData.home_team,
    away_team:          matchData.away_team,
    home_team_id:       matchData.home_team_id,
    away_team_id:       matchData.away_team_id,
    stage:              matchData.stage,
    scheduled_at:       matchData.scheduled_at,
    venue_name:         matchData.venue_name,
    stats:              enrichedStats,
    news_context:       newsRows,
    sentiment_context: {
      home: sentMap[matchData.home_team_id] || null,
      away: sentMap[matchData.away_team_id] || null,
    },
    correlationId: $('Init').first().json.correlationId,
  }
}];

const rl = $input.first().json;
const current = parseInt(rl.value || '0');
return [{ json: { rate_limited: current >= 20, current } }];

const pred = $input.first().json;
const featData = $('Aggregate Feature Set').item.json;

if (pred.gpt_error) return [{ json: { persist: false, gpt_error: true, match_id: pred.match_id } }];
if (!pred.home_win_prob || !pred.justification) return [{ json: { persist: false, incomplete: true } }];

return [{ json: { persist: true, prediction: pred, feature_snapshot: featData.stats, match_id: featData.match_id } }];
